update public.observation_taxonomy ot
set
  default_value_type = 'quantity',
  default_unit = seed.value_unit,
  interpretation_guide = coalesce(ot.interpretation_guide, '{}'::jsonb)
    || jsonb_build_object(
      'seed_wave', 'secondary_rom_l3_wave11',
      'plain_status', '처방 판단 가능',
      'capability_code', seed.capability_code,
      'capability_label_ko', seed.capability_label_ko,
      'direction', 'higher_is_better',
      'laterality_required', seed.laterality_required,
      'decision_bands', jsonb_build_array(
        'ready: ' || seed.ready_operator || seed.ready_value || seed.value_unit,
        'caution: ' || seed.caution_operator || seed.caution_value || seed.value_unit,
        'regress: ' || seed.regress_operator || seed.regress_value || seed.value_unit
      ),
      'safety_note', seed.review_note
    ),
  updated_at = now()
from seed
where ot.code = seed.observation_code
  and ot.code_system = 'http://physiokorea.com/fhir/observation';
