update public.movement_capability_observation_mappings map
set
  default_unit = seed.value_unit,
  value_type_hint = 'quantity',
  metadata = coalesce(map.metadata, '{}'::jsonb)
    || jsonb_build_object(
      'seed_wave', 'secondary_rom_l3_wave11',
      'completion_level', 'L3',
      'plain_status', '처방 판단 가능',
      'capability_code', seed.capability_code,
      'normalization', jsonb_build_object(
        'canonical_unit', seed.value_unit,
        'laterality_required', seed.laterality_required
      )
    ),
  updated_at = now()
from seed
where map.observation_code = seed.observation_code
  and map.status = 'active';
