update public.exercise_requirements er
set
  value_unit = coalesce(er.value_unit, seed.value_unit),
  metadata = coalesce(er.metadata, '{}'::jsonb)
    || jsonb_build_object(
      'seed_wave', 'secondary_rom_l3_wave11',
      'requirement_rule_family', 'secondary_rom_l3_wave11',
      'l3_rule_capability_code', seed.capability_code
    ),
  updated_at = now()
from seed
join public.movement_capabilities mc
  on mc.capability_code = seed.capability_code
where er.capability_id = mc.id
  and er.status = 'active';
